# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json

class Inventory:
    def __init__(self, player_id):
        self.player_id = player_id
        self.items = {}

    def add_item(self, item_id, quantity):
        if item_id in self.items:
            self.items[item_id] += quantity
        else:
            self.items[item_id] = quantity

    def remove_item(self, item_id, quantity):
        if item_id in self.items and self.items[item_id] >= quantity:
            self.items[item_id] -= quantity
            if self.items[item_id] == 0:
                del self.items[item_id]
            return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}
        self.inventory_by_player = {}

    async def handle_connection(self, websocket, path):
        player_id = await websocket.recv()
        self.players[player_id] = websocket
        self.inventory_by_player[player_id] = Inventory(player_id)

        try:
            async for message in websocket:
                data = json.loads(message)
                if data['type'] == 'add_item':
                    self.inventory_by_player[player_id].add_item(data['item_id'], data['quantity'])
                elif data['type'] == 'remove_item':
                    success = self.inventory_by_player[player_id].remove_item(data['item_id'], data['quantity'])
                    if success:
                        await self.notify_others(player_id, data)
        finally:
            del self.players[player_id]
            del self.inventory_by_player[player_id]

    async def notify_others(self, player_id, data):
        for other_player_id, websocket in self.players.items():
            if other_player_id != player_id:
                await websocket.send(json.dumps(data))

start_server = websockets.serve(GameServer().handle_connection, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()